pub struct Note {
    pub title: String,
    body: String,
}

impl Note {
    pub fn new(title: String, body: String) -> Note {
        Note { title, body }
    }

    pub fn word_count(&self) -> usize {
        self.body.split_whitespace().count()
    }
}

use rust_notes::{count_words, Note};

#[test]
fn crate_root_exposes_the_api() {
    assert_eq!(count_words("one two three"), 3);

    let note = Note::new(String::from("Rust"), String::from("modules hide layout"));
    assert_eq!(note.title, "Rust");
    assert_eq!(note.word_count(), 3);
}
